        current_block = None

        # Iterate through all possible Unicode codepoints (up to U+10FFFF)
        for codepoint in range(0x110000):
            try:
                char = chr(codepoint)
                name = unicodedata.name(char, f"<control-{codepoint:04X}>")
                block = get_block_name(codepoint)

                # Write block header if we're entering a new block
                if block != current_block:
                    f.write(f"\n# {block}\n")
                    current_block = block

                # Write character info
                f.write(f"{char}, U+{codepoint:04X}, {name};\n")

            except ValueError:
                # Skip invalid codepoints (surrogates, etc.)
                continue

    print(f"Unicode character listing written to {output_file}")
    print("You can now edit the file to add '+' or '-' after block headers to include/exclude them.")

